//! # E_8 / Leech residual-energy measurement on **real FLUX weight tiles**.
//!
//! Increment (2) of the Unsound-FLUX → real-runtime evolution: the "superior
//! frames at the same bit budget" claim, measured on real FLUX-1-schnell weight
//! data rather than synthetic uniform samples.
//!
//! ## The measurement
//!
//! A coarse code (here Q8_0, a scalar/cubic quantizer: each coordinate rounded
//! independently to a uniform grid of edge `step`) leaves a per-coordinate
//! residual `r_i = x_i − round(x_i/step)·step ∈ [−step/2, step/2)`. The residual
//! *energy* `E[‖r‖²]` is what propagates into the output (and, via the energy
//! gate, sets the admit rate). A **lattice** quantizer of the same dimension and
//! the *same cell volume* (same bit budget) has a strictly lower normalized
//! second moment than the cube:
//!
//! ```text
//!   G(ℤⁿ) = 1/12 ≈ 0.0833   (scalar / cubic — what Q8_0 is)
//!   G(E_8)        ≈ 0.0717   (−14% energy)
//!   G(Λ₂₄)        ≈ 0.0658   (−21% energy)
//! ```
//!
//! Those are the *theoretical* floors on uniform data. The point of THIS module
//! is to confirm the ordering survives on **real FLUX weight tiles** — whose
//! distribution is not uniform — by quantizing the actual dequantized weight
//! values at a matched cell volume with the cube vs E_8 vs Leech and comparing
//! the measured residual energy. If the lattice does NOT beat the cube on real
//! tiles, that is reported honestly; nothing here asserts an unproven win.
//!
//! All three quantizers are normalized to the **same per-coordinate cell volume**
//! `step` so the comparison is at equal bit budget:
//!   * cube:  round each coord to the nearest multiple of `step`;
//!   * E_8:   scale the 8-vector into the lattice's natural cell, decode with
//!            [`crate::e8_quantizer::nearest_e8_standard`], scale back;
//!   * Leech: same with [`crate::leech_quantizer::nearest_leech`] (Conway
//!            min-norm-32 coords, whose per-coordinate cell volume is `8^(1/...)`
//!            handled by the standard volume normaliser).
//!
//! The lattice generator matrices are scaled to unit covolume first (so a cell
//! of volume `step^n`), making "same bit budget" exact.

#![allow(dead_code)]

use crate::e8_quantizer::{e8_err_sq_standard, z8_err_sq_standard};
use crate::leech_quantizer::{nearest_leech, LEECH_DIM};
use crate::math::dequantize_q8_0_flat;

/// E_8 has covolume 1 in standard coordinates, so a cube of the same covolume is
/// the unit cube and the bit budgets already match — no extra normaliser.
///
/// Leech in this crate's Conway coordinates has covolume `det = 2^36`, i.e.
/// per-coordinate cell volume `V^(1/24) = 2^(36/24) = 2^1.5 = √8`. To compare
/// Leech against a cube of equal per-coordinate cell, the cube edge for the
/// Leech comparison must be that same `√8`. We fold this by scaling the input
/// into Leech coordinates so one Leech cell has unit per-coordinate volume.
const LEECH_CELL_EDGE: f64 = 2.828_427_124_746_19; // √8

/// Squared quantization error of a 24-vector under the **scalar/cubic** code at
/// the Leech-matched cell edge `√8` (so the bit budget equals one Leech cell).
fn z24_err_sq_leech_matched(x: &[f64; LEECH_DIM]) -> f64 {
    let mut d = 0.0f64;
    for &xi in x {
        let q = (xi / LEECH_CELL_EDGE).round() * LEECH_CELL_EDGE;
        let e = xi - q;
        d += e * e;
    }
    d
}

/// Squared quantization error of a 24-vector under the **full Leech** decoder,
/// at the same `√8` per-coordinate cell (Conway coords are already that scale).
fn leech_err_sq(x: &[f64; LEECH_DIM]) -> f64 {
    let q = nearest_leech(*x);
    let mut d = 0.0f64;
    for i in 0..LEECH_DIM {
        let e = x[i] - q[i] as f64;
        d += e * e;
    }
    d
}

/// Result bundle with both matched scalar baselines.
#[derive(Clone, Copy, Debug, Default)]
pub struct FluxTileLatticeReport {
    pub e8_tiles: usize,
    pub leech_tiles: usize,
    /// Mean per-tile residual energy: scalar (unit cube) vs E_8, on 8-D tiles.
    pub scalar_e8_energy: f64,
    pub e8_energy: f64,
    /// Mean per-tile residual energy: scalar (√8 cube) vs Leech, on 24-D tiles.
    pub scalar_leech_energy: f64,
    pub leech_energy: f64,
}

impl FluxTileLatticeReport {
    /// E_8 fractional energy reduction vs the matched scalar baseline.
    pub fn e8_reduction(&self) -> f64 {
        if self.scalar_e8_energy <= 0.0 {
            0.0
        } else {
            1.0 - self.e8_energy / self.scalar_e8_energy
        }
    }
    /// Leech fractional energy reduction vs the matched scalar baseline.
    pub fn leech_reduction(&self) -> f64 {
        if self.scalar_leech_energy <= 0.0 {
            0.0
        } else {
            1.0 - self.leech_energy / self.scalar_leech_energy
        }
    }
    /// True iff BOTH lattices strictly beat their matched scalar baseline.
    pub fn lattice_is_superior(&self) -> bool {
        self.e8_energy < self.scalar_e8_energy && self.leech_energy < self.scalar_leech_energy
    }
}

/// The window (cell edge) the E_8 comparison uses on the real weight values. We
/// rescale each weight slab so its dynamic range spans a few lattice cells (the
/// regime where the second-moment ordering is meaningful — too coarse and every
/// quantizer rounds to 0; too fine and the residual vanishes for all). The edge
/// is chosen from the slab's own RMS so the test is distribution-adaptive and
/// not a hand-tuned constant.
fn adaptive_cell_edge(values: &[f32]) -> f64 {
    if values.is_empty() {
        return 1.0;
    }
    let mean = values.iter().map(|&v| v as f64).sum::<f64>() / values.len() as f64;
    let var = values
        .iter()
        .map(|&v| {
            let d = v as f64 - mean;
            d * d
        })
        .sum::<f64>()
        / values.len() as f64;
    // edge ≈ one standard deviation: spans the bulk in O(1) cells.
    (var.sqrt()).max(1e-6)
}

/// Measure E_8 vs scalar residual energy on **real dequantized FLUX weights**.
///
/// `weights` is a flat slab of dequantized f32 weight values (e.g. one FLUX
/// linear's Q8_0 tensor dequantized). It is chunked into 8-vectors; each is
/// scaled into the lattice's natural cell (edge = `adaptive_cell_edge`),
/// quantized with the cube and with E_8 at that **same** cell, and the residual
/// energies (rescaled back to weight units) are accumulated.
pub fn measure_e8_residual_on_weights(weights: &[f32]) -> (usize, f64, f64) {
    let edge = adaptive_cell_edge(weights);
    let n = weights.len() / 8;
    if n == 0 {
        return (0, 0.0, 0.0);
    }
    let mut scalar_acc = 0.0f64;
    let mut e8_acc = 0.0f64;
    let inv = 1.0 / edge;
    let edge2 = edge * edge;
    for t in 0..n {
        let base = t * 8;
        let mut xs = [0.0f64; 8];
        for i in 0..8 {
            // scale into unit-cell coordinates: one lattice cell == one weight
            // `edge`, so cube and E_8 share the bit budget exactly.
            xs[i] = weights[base + i] as f64 * inv;
        }
        // residual energies are in unit-cell coords; ×edge² returns weight units.
        scalar_acc += z8_err_sq_standard(&xs) * edge2;
        e8_acc += e8_err_sq_standard(&xs) * edge2;
    }
    (n, scalar_acc / n as f64, e8_acc / n as f64)
}

/// Measure Leech vs scalar residual energy on **real dequantized FLUX weights**,
/// chunked into 24-vectors. Same bit budget: the cube edge is the Leech cell
/// edge `√8` after scaling each tile by `1/adaptive_cell_edge`.
pub fn measure_leech_residual_on_weights(weights: &[f32]) -> (usize, f64, f64) {
    let edge = adaptive_cell_edge(weights);
    let n = weights.len() / LEECH_DIM;
    if n == 0 {
        return (0, 0.0, 0.0);
    }
    let mut scalar_acc = 0.0f64;
    let mut leech_acc = 0.0f64;
    // Scale weights so the Leech √8 cell == one weight `edge`: divide by edge,
    // then multiply into Leech coords by √8 so a √8-cube of the lattice matches.
    let to_leech = LEECH_CELL_EDGE / edge;
    let back2 = (edge / LEECH_CELL_EDGE) * (edge / LEECH_CELL_EDGE);
    for t in 0..n {
        let base = t * LEECH_DIM;
        let mut xs = [0.0f64; LEECH_DIM];
        for i in 0..LEECH_DIM {
            xs[i] = weights[base + i] as f64 * to_leech;
        }
        scalar_acc += z24_err_sq_leech_matched(&xs) * back2;
        leech_acc += leech_err_sq(&xs) * back2;
    }
    (n, scalar_acc / n as f64, leech_acc / n as f64)
}

/// Run both measurements on a dequantized weight slab and bundle the report.
pub fn measure_flux_tile_lattice(weights: &[f32]) -> FluxTileLatticeReport {
    let (e8_tiles, scalar_e8, e8) = measure_e8_residual_on_weights(weights);
    let (leech_tiles, scalar_leech, leech) = measure_leech_residual_on_weights(weights);
    FluxTileLatticeReport {
        e8_tiles,
        leech_tiles,
        scalar_e8_energy: scalar_e8,
        e8_energy: e8,
        scalar_leech_energy: scalar_leech,
        leech_energy: leech,
    }
}

/// Dequantize a Q8_0 weight slab (flat 34-byte block stream) and measure the
/// lattice residual energy on the real values. `total` is the number of f32
/// weights the slab encodes.
pub fn measure_flux_q8_tile_lattice(q8_bytes: &[u8], total: usize) -> FluxTileLatticeReport {
    let weights = dequantize_q8_0_flat(q8_bytes, total);
    measure_flux_tile_lattice(&weights)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::leech_quantizer::SplitMix64;

    #[test]
    fn lattice_beats_scalar_on_uniform_in_cell_residuals() {
        // Synthetic but honest: uniform-in-cell residuals are exactly the regime
        // the normalized-second-moment ordering governs. The lattice MUST win.
        let mut rng = SplitMix64::new(0xF10C_1A77_1CE0_0024);
        let mut w = Vec::with_capacity(24 * 4000);
        for _ in 0..(24 * 4000) {
            // values spread over a few cells so quantization is non-trivial.
            w.push(rng.next_in(6.0) as f32);
        }
        let rep = measure_flux_tile_lattice(&w);
        assert!(rep.e8_tiles > 0 && rep.leech_tiles > 0);
        // On uniform data both lattices beat the cube (that IS their second
        // moment); this guards the harness arithmetic, not the FLUX claim.
        assert!(
            rep.e8_energy < rep.scalar_e8_energy,
            "E8 must beat scalar on uniform data: e8={:.6} scalar={:.6}",
            rep.e8_energy,
            rep.scalar_e8_energy
        );
        assert!(
            rep.leech_energy < rep.scalar_leech_energy,
            "Leech must beat scalar on uniform data: leech={:.6} scalar={:.6}",
            rep.leech_energy,
            rep.scalar_leech_energy
        );
        // Leech should beat E8 in the energy-reduction sense.
        assert!(rep.leech_reduction() > 0.0);
        assert!(rep.e8_reduction() > 0.0);
    }

    #[test]
    fn empty_slab_is_safe() {
        let rep = measure_flux_tile_lattice(&[]);
        assert_eq!(rep.e8_tiles, 0);
        assert_eq!(rep.leech_tiles, 0);
        assert!(!rep.lattice_is_superior());
    }

    #[test]
    fn q8_roundtrip_dequant_then_measure() {
        // Build a tiny Q8_0 slab and confirm the dequant+measure path runs.
        // One block: f16 scale=1.0 (0x3C00) + 32 i8 ramp values.
        let mut bytes = Vec::new();
        bytes.extend_from_slice(&0x3C00u16.to_le_bytes()); // f16 1.0
        for j in 0..32i8 {
            bytes.push((j - 16) as u8);
        }
        let rep = measure_flux_q8_tile_lattice(&bytes, 32);
        // 32 values ⇒ 4 E8 tiles, 1 Leech tile.
        assert_eq!(rep.e8_tiles, 4);
        assert_eq!(rep.leech_tiles, 1);
    }
}
